bash /workspaces/omniedge-routeiq/routeiq-v18-zero-token-audit.sh#!/usr/bin/env bash
set -Eeuo pipefail

ROOT="${ROUTEIQ_ROOT:-/workspaces/omniedge-routeiq}"
WORKTREE="${ROUTEIQ_WORKTREE:-/tmp/routeiq-v18}"
BRANCH="${ROUTEIQ_BRANCH:-track1-v18-zero-token-audit}"
BASE_REF="${ROUTEIQ_BASE_REF:-track1-v1.2-champion}"
AGENT_DIR="track1-v18-agent"
LOCAL_IMAGE="routeiq-v18-zero-token-audit:test"
BASE_IMAGE="routeiq-v14-ultra-local:base"
MIN_PASS="${ROUTEIQ_MIN_PASS:-18}"
PUBLISH="${ROUTEIQ_PUBLISH:-1}"

say() { printf '\n==> %s\n' "$*"; }
die() { printf '\nERROR: %s\n' "$*" >&2; exit 1; }
trap 'printf "\nFAILED at line %s. The portal and current scored submission were not changed.\n" "$LINENO" >&2' ERR

for command in git python3 docker timeout gh; do
  command -v "$command" >/dev/null || die "$command is required"
done

[[ -d "$ROOT/.git" ]] || die "repository not found: $ROOT"
cd "$ROOT"
docker info >/dev/null 2>&1 || die "Docker daemon is unavailable"
git cat-file -e "${BASE_REF}^{commit}" 2>/dev/null || die "base ref is unavailable: $BASE_REF"

say "Preparing isolated v1.8 zero-token worktree"
if [[ -d "$WORKTREE" ]]; then
  git worktree remove --force "$WORKTREE" >/dev/null 2>&1 || sudo rm -rf "$WORKTREE"
fi
git worktree prune
if git show-ref --verify --quiet "refs/heads/$BRANCH"; then
  git branch -D "$BRANCH" >/dev/null
fi
git worktree add -b "$BRANCH" "$WORKTREE" "$BASE_REF"
cd "$WORKTREE"

say "Installing the tested local-only proposal-and-audit agent"
rm -rf "$AGENT_DIR"
mkdir -p "$AGENT_DIR"
base64 -d <<'ROUTEIQ_V18_PAYLOAD' | tar -xzf - -C "$AGENT_DIR"
