ROUTEIQ_V18_PAYLOAD
chmod -R u+rwX "$AGENT_DIR"

say "Running syntax and unit tests"
(
  cd "$AGENT_DIR"
  python3 -m py_compile agent.py local/*.py
  python3 -m unittest discover -s tests -v
)

say "Building local benchmark image"
if docker image inspect "$BASE_IMAGE" >/dev/null 2>&1; then
  cat > "$AGENT_DIR/Dockerfile.local" <<'DOCKER'
FROM routeiq-v14-ultra-local:base

ENV PYTHONDONTWRITEBYTECODE=1 \
    PYTHONUNBUFFERED=1 \
    ROUTEIQ_LOCAL_ONLY=1 \
    ROUTEIQ_TOTAL_BUDGET_SECONDS=575 \
    QWEN_ENABLED=1 \
    QWEN_BINARY=/app/llama-completion \
    QWEN_MODEL_PATH=/app/models/Qwen3-4B-Q4_K_M.gguf \
    QWEN_THREADS=2 \
    QWEN_CONTEXT_SIZE=4096 \
    QWEN_PROPOSAL_MODE=nonthinking \
    QWEN_PROPOSAL_MAX_TOKENS=1600 \
    QWEN_PROPOSAL_TIMEOUT_SECONDS=220 \
    QWEN_AUDIT_ENABLED=1 \
    QWEN_AUDIT_MODE=thinking \
    QWEN_AUDIT_MAX_TOKENS=1400 \
    QWEN_AUDIT_TIMEOUT_SECONDS=300 \
    QWEN_REASONING_BUDGET=640 \
    QWEN_PRESENCE_PENALTY=0.0

COPY agent.py /app/agent.py
COPY local /app/local

ENTRYPOINT ["python3", "/app/agent.py"]
DOCKER
  docker build --progress=plain -f "$AGENT_DIR/Dockerfile.local" -t "$LOCAL_IMAGE" "$AGENT_DIR"
else
  docker build --progress=plain -t "$LOCAL_IMAGE" "$AGENT_DIR"
fi

BENCH_ROOT="$(mktemp -d)"
mkdir -p "$BENCH_ROOT/input" "$BENCH_ROOT/output"
chmod 777 "$BENCH_ROOT/output"
cp "$AGENT_DIR/bench/tasks.json" "$BENCH_ROOT/input/tasks.json"

say "Running 19-task zero-Fireworks benchmark under 2 CPU / 4 GB"
START="$(date +%s)"
set +e
timeout 590 docker run --rm \
  --network none \
  --cpus=2 \
  --memory=4g \
  -v "$BENCH_ROOT/input:/input:ro" \
  -v "$BENCH_ROOT/output:/output" \
  "$LOCAL_IMAGE" 2>&1 | tee "$BENCH_ROOT/container.log"
RUN_STATUS="${PIPESTATUS[0]}"
set -e
END="$(date +%s)"
printf '%s\n' "$((END - START))" > "$BENCH_ROOT/runtime.txt"

[[ "$RUN_STATUS" -eq 0 ]] || die "candidate container failed or exceeded the runtime ceiling"
[[ -s "$BENCH_ROOT/output/results.json" ]] || die "candidate produced no results.json"

set +e
python3 "$AGENT_DIR/bench/score_benchmark.py" \
  "$BENCH_ROOT/input/tasks.json" \
  "$BENCH_ROOT/output/results.json" \
  "$BENCH_ROOT/runtime.txt" | tee "$BENCH_ROOT/score.log"
set -e

GATE="$(python3 - "$BENCH_ROOT/output/benchmark-report.json" "$MIN_PASS" <<'PY'
import json, sys
report = json.load(open(sys.argv[1], encoding="utf-8"))
minimum = int(sys.argv[2])
passed = int(report.get("passed", 0))
missing = report.get("missing", [])
runtime = float(report.get("runtime_seconds", 9999))
if missing:
    raise SystemExit(f"GATE FAILED: missing answers remain: {missing}")
if passed < minimum:
    raise SystemExit(f"GATE FAILED: only {passed}/19 passed; minimum is {minimum}")
if runtime > 560:
    raise SystemExit(f"GATE FAILED: runtime {runtime:.1f}s exceeds 560s")
print("PERFECT_LOCAL" if passed == 19 else f"ZERO_TOKEN_EXPERIMENT_{passed}_OF_19")
PY
)"
printf 'V18_GATE=%s\n' "$GATE"

ARCH="$(docker image inspect --format '{{.Architecture}}' "$LOCAL_IMAGE")"
SIZE="$(docker image inspect --format '{{.Size}}' "$LOCAL_IMAGE")"
[[ "$ARCH" == "amd64" ]] || die "candidate architecture is $ARCH"
[[ "$SIZE" -lt 8000000000 ]] || die "candidate image is too large: $SIZE bytes"

say "Creating GitHub Actions publication workflow"
mkdir -p .github/workflows
cat > .github/workflows/publish-track1-v18.yml <<'YAML'
name: Publish RouteIQ v1.8 Zero Token Audit

on:
  push:
    branches:
      - track1-v18-zero-token-audit
    paths:
      - "track1-v18-agent/**"
      - ".github/workflows/publish-track1-v18.yml"

permissions:
  contents: read
  packages: write

concurrency:
  group: publish-routeiq-v18-zero-token-audit
  cancel-in-progress: false

jobs:
  publish:
    runs-on: ubuntu-latest
    timeout-minutes: 40

    steps:
      - name: Checkout candidate branch
        uses: actions/checkout@v4

      - name: Free runner disk space
        run: |
          sudo rm -rf /usr/local/lib/android /usr/share/dotnet /opt/ghc || true
          df -h

      - name: Set up Docker Buildx
        uses: docker/setup-buildx-action@v3

      - name: Log in to GHCR
        uses: docker/login-action@v3
        with:
          registry: ghcr.io
          username: ${{ github.actor }}
          password: ${{ secrets.GITHUB_TOKEN }}

      - name: Build and publish linux/amd64 candidate
        uses: docker/build-push-action@v6
        with:
          context: ./track1-v18-agent
          file: ./track1-v18-agent/Dockerfile
          platforms: linux/amd64
          push: true
          provenance: false
          sbom: false
          tags: ghcr.io/${{ github.repository_owner }}/omniedge-routeiq-track1:c-v18-${{ github.sha }}
          cache-from: type=gha
          cache-to: type=gha,mode=max
YAML

find "$AGENT_DIR" -type d -name __pycache__ -prune -exec rm -rf {} +
find "$AGENT_DIR" -type f -name '*.pyc' -delete
git add "$AGENT_DIR" .github/workflows/publish-track1-v18.yml
git commit -m "feat(track1): add v1.8 zero-token local audit candidate"
COMMIT="$(git rev-parse HEAD)"

if [[ "$PUBLISH" != "1" ]]; then
  say "Benchmark gate passed; publication skipped"
  printf 'Gate: %s\nCommit: %s\nReport: %s\n' "$GATE" "$COMMIT" "$BENCH_ROOT/output/benchmark-report.json"
  exit 0
fi

say "Pushing the experimental branch"
git push -u origin "$BRANCH"

say "Waiting for GitHub Actions publication"
RUN_ID=""
for _ in $(seq 1 40); do
  RUN_ID="$(gh api "repos/kaulastudies/omniedge-routeiq/actions/runs?branch=$BRANCH&per_page=10" \
    --jq ".workflow_runs[] | select(.head_sha == \"$COMMIT\") | .id" 2>/dev/null | head -n1 || true)"
  [[ -n "$RUN_ID" ]] && break
  sleep 5
done
[[ -n "$RUN_ID" ]] || die "workflow did not appear"

RUN_URL="$(gh run view "$RUN_ID" --json url --jq '.url')"
printf 'Workflow: %s\n' "$RUN_URL"
gh run watch "$RUN_ID" --exit-status

OWNER="$(gh repo view --json owner --jq '.owner.login')"
IMAGE="ghcr.io/${OWNER,,}/omniedge-routeiq-track1:c-v18-${COMMIT}"

say "Verifying anonymous public pull"
docker logout ghcr.io >/dev/null 2>&1 || true
docker image rm "$IMAGE" >/dev/null 2>&1 || true
docker pull "$IMAGE" >/dev/null
PULLED_ARCH="$(docker image inspect --format '{{.Architecture}}' "$IMAGE")"
[[ "$PULLED_ARCH" == "amd64" ]] || die "published candidate is not linux/amd64"

PRIVATE_DIR="/workspaces/.routeiq-private"
PRIVATE_FILE="$PRIVATE_DIR/v18-candidate.txt"
mkdir -p "$PRIVATE_DIR"
chmod 700 "$PRIVATE_DIR"
{
  printf 'PRIVATE — DO NOT POST IN DISCORD, README, OR SCREENSHOTS\n'
  printf 'image=%s\n' "$IMAGE"
  printf 'commit=%s\n' "$COMMIT"
  printf 'gate=%s\n' "$GATE"
  printf 'benchmark_report=%s\n' "$BENCH_ROOT/output/benchmark-report.json"
  printf 'benchmark_results=%s\n' "$BENCH_ROOT/output/results.json"
  printf 'container_log=%s\n' "$BENCH_ROOT/container.log"
  printf 'workflow=%s\n' "$RUN_URL"
} > "$PRIVATE_FILE"
chmod 600 "$PRIVATE_FILE"

say "v1.8 zero-token candidate published successfully"
printf 'Gate: %s\nPrivate candidate record: %s\n' "$GATE" "$PRIVATE_FILE"
printf 'The portal and current scored submission were not changed.\n'
printf 'Do not submit until the benchmark result is reviewed.\n'
